// n8n-marcin/16-weekly-summary.json — Gather Weekly Data
// Purpose: Collect stats from Qdrant for weekly summary
// NOT for: sending messages

const qdrantUrl = 'http://qdrant:6333';

// Date range: last 7 days
const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const weekAgoStr = weekAgo.toISOString();

const qdrantScroll = async (filter, limit) => {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: qdrantUrl + '/collections/krasnik_news/points/scroll',
      body: { limit, with_payload: true, with_vector: false, filter },
      json: true
    });
    return r.result?.points || [];
  } catch (e) { return []; }
};

const qdrantCount = async (filter) => {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: qdrantUrl + '/collections/krasnik_news/points/count',
      body: { filter, exact: true },
      json: true
    });
    return r.result?.count || 0;
  } catch (e) { return 0; }
};

// Parallel queries
const [totalArticles, recentArticles, briefings, preferences, feedbacks, przetargi, sessions] = await Promise.all([
  // Total articles in DB
  qdrantCount({}),
  // Articles from last 7 days (no system categories)
  qdrantScroll({
    must: [{ key: 'date', range: { gte: weekAgoStr } }],
    must_not: [
      { key: 'category', match: { value: 'briefing' } },
      { key: 'category', match: { value: 'briefing-index' } },
      { key: 'category', match: { value: 'marcin-preference' } },
      { key: 'category', match: { value: 'marcin-last-post' } },
      { key: 'category', match: { value: 'marcin-style-feedback' } },
      { key: 'category', match: { value: 'sesja-rady-notified' } },
      { key: 'category', match: { value: 'bip-przetarg-notified' } }
    ]
  }, 200),
  // Briefings from last 7 days
  qdrantScroll({
    must: [
      { key: 'category', match: { value: 'briefing' } },
      { key: 'date', range: { gte: weekAgoStr } }
    ]
  }, 10),
  // All preferences
  qdrantScroll({ must: [{ key: 'category', match: { value: 'marcin-preference' } }] }, 100),
  // All feedbacks
  qdrantScroll({ must: [{ key: 'category', match: { value: 'marcin-style-feedback' } }] }, 20),
  // Przetargi notified
  qdrantScroll({
    must: [
      { key: 'category', match: { value: 'bip-przetarg-notified' } },
      { key: 'notified_at', range: { gte: weekAgoStr } }
    ]
  }, 50),
  // Sessions notified
  qdrantScroll({ must: [{ key: 'category', match: { value: 'sesja-rady-notified' } }] }, 20)
]);

// Analyze sources
const sourceCounts = {};
for (const a of recentArticles) {
  const src = a.payload?.source || 'unknown';
  sourceCounts[src] = (sourceCounts[src] || 0) + 1;
}
const topSources = Object.entries(sourceCounts).sort((a, b) => b[1] - a[1]).slice(0, 5);

// Analyze topics from preferences
const topicCounts = {};
for (const p of preferences) {
  for (const t of (p.payload?.topics || [])) {
    topicCounts[t] = (topicCounts[t] || 0) + 1;
  }
}
const topTopics = Object.entries(topicCounts).sort((a, b) => b[1] - a[1]).slice(0, 5);

// Count posts generated (from preferences = each preference = 1 post generated)
const weekPrefs = preferences.filter(p => (p.payload?.date || '') >= weekAgoStr);

return [{ json: {
  totalArticles,
  weekArticles: recentArticles.length,
  briefingCount: briefings.length,
  postsGenerated: weekPrefs.length,
  feedbackCount: feedbacks.length,
  przetargiCount: przetargi.length,
  sessionsCount: sessions.length,
  topSources,
  topTopics,
  weekAgoStr: weekAgoStr.slice(0, 10),
  nowStr: now.toISOString().slice(0, 10)
} }];

const GROUP_JID = $env.WHATSAPP_GROUP_JID || '120363426348074659@g.us';
// n8n-marcin/16-weekly-summary.json — Format Weekly Summary
// Purpose: Format WhatsApp weekly summary message
// NOT for: data gathering

const d = $input.first().json;

// Format dates nicely: "21.02 → 28.02"
const from = d.weekAgoStr.slice(8,10) + '.' + d.weekAgoStr.slice(5,7);
const to = d.nowStr.slice(8,10) + '.' + d.nowStr.slice(5,7);

let msg = '📊 *Tydzień ' + from + ' → ' + to + '*\n\n';

// Compact stats in 2 lines
msg += '📰 ' + d.weekArticles + ' artykułów · 📋 ' + d.briefingCount + ' briefingów · ✍️ ' + d.postsGenerated + ' postów FB\n';
msg += '📋 ' + d.przetargiCount + ' przetargów · 🗳️ ' + d.sessionsCount + ' sesji · ❤️ ' + d.feedbackCount + ' feedbacków\n\n';

// Top sources — compact
if (d.topSources && d.topSources.length > 0) {
  msg += '🏆 *Źródła:* ';
  msg += d.topSources.map(([src, count]) => src + ' (' + count + ')').join(', ');
  msg += '\n\n';
}

// Top topics — compact
if (d.topTopics && d.topTopics.length > 0) {
  msg += '❤️ *Twoje tematy:* ';
  msg += d.topTopics.map(([topic, count]) => topic + ' (' + count + 'x)').join(', ');
  msg += '\n\n';
}

// Tips — friendlier
if (d.postsGenerated === 0) {
  msg += '💡 W tym tygodniu żadnego posta — po briefingu odpisz numerami!\n\n';
} else if (d.feedbackCount === 0) {
  msg += '💡 Daj feedback do postów (np. _krócej_, _więcej emoji_) — system się uczy!\n\n';
}

msg += 'Dobrego weekendu! 🎉';

return [{ json: { response: msg, chatId: GROUP_JID } }];
